#!/usr/bin/env python3
"""TASK-4: Add stdin-based task ID input to workflow-cli retry command"""
import base64, json, subprocess, sys
from pathlib import Path

TASK_ID = "TASK-4"
STEPS = json.loads('[{"before_b64": "", "after_b64": "", "target": "/Users/tony/programming/castep_workflow_framework/workflow-cli/src/main.rs", "index": 0, "is_create": false}, {"before_b64": "ICAgICAgICBDb21tYW5kczo6UmV0cnkgeyBzdGF0ZV9maWxlLCB0YXNrX2lkcyB9ID0+IHsKICAgICAgICAgICAgbGV0IG11dCBzdGF0ZSA9IGxvYWRfc3RhdGVfZm9yX3Jlc3VtZSgmc3RhdGVfZmlsZSk/OwogICAgICAgICAgICBjbWRfcmV0cnkoJm11dCBzdGF0ZSwgJnRhc2tfaWRzKT87CiAgICAgICAgICAgIE9rKCgpKQogICAgICAgIH0=", "after_b64": "", "target": "/Users/tony/programming/castep_workflow_framework/workflow-cli/src/main.rs", "index": 1, "is_create": false}, {"before_b64": "", "after_b64": "", "target": "/Users/tony/programming/castep_workflow_framework/workflow-cli/src/main.rs", "index": 2, "is_create": false}]')

for step in STEPS:
    before = base64.b64decode(step["before_b64"]).decode()
    after = base64.b64decode(step["after_b64"]).decode()
    target = step["target"]
    idx = step["index"]
    is_create = step["is_create"]

    if is_create:
        target_path = Path(target)
        target_path.parent.mkdir(parents=True, exist_ok=True)
        target_path.write_text(after)
        print(f"OK {TASK_ID} change {idx}: created {target}")
    else:
        target_path = Path(target)
        content = target_path.read_text()
        if before not in content:
            print(f"FAILED {TASK_ID} change {idx}: pattern not found in {target}", file=sys.stderr)
            print(f"Expected (first 200 chars): {repr(before[:200])}", file=sys.stderr)
            sys.exit(1)

        result = subprocess.run(
            ["sd", "-F", "-A", "-n", "1", "--", before, after, target],
            capture_output=True, text=True,
        )
        if result.returncode != 0:
            print(f"FAILED {TASK_ID} change {idx}: sd error: {result.stderr}", file=sys.stderr)
            sys.exit(result.returncode)

        new_content = target_path.read_text()
        if after and after not in new_content:
            print(f"FAILED {TASK_ID} change {idx}: replacement not found after apply", file=sys.stderr)
            sys.exit(1)

        print(f"OK {TASK_ID} change {idx}: applied to {target}")

print(f"OK {TASK_ID}: all changes applied")
